+
+/**
+ * Runs one agent turn. A delegate_task starts a nested run, then resumes this
+ * agent with the nested run's tool_result JSON as its next message.
+ */
+async function* executeAgentConversation(
+  agentId: string,
+  initialMessage: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationPath: string[],
+): AsyncGenerator<StreamResponse, AgentRunResult> {
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+  if (!provider || !agentConfig) {
+    return { text: "", error: `Agent '${agentId}' not found or provider not available` };
+  }
+
+  const accumulatedText: string[] = [];
+  let message = initialMessage;
+  let toolSequence = 0;
+
+  while (true) {
+    let resumeMessage: string | undefined;
+    try {
+      const providerRequest: ProviderChatRequest = {
+        message,
+        sessionId: request.sessionId,
+        requestId: request.requestId,
+        workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+      };
+
+      for await (const response of provider.executeChat(providerRequest, {
+        debugMode,
+        abortController,
+        temperature: agentConfig.config?.temperature,
+        maxTokens: agentConfig.config?.maxTokens,
+      })) {
+        if (response.type === "tool_use" && response.toolName === "delegate_task") {
+          const input = (response.toolInput ?? {}) as DelegateTaskInput;
+          const toolUseId = response.toolUseId || `${agentId}-delegate-${++toolSequence}`;
+          yield toolUseStreamResponse(agentId, toolUseId, input, request.sessionId);
+
+          const requestedAgentId = typeof input.agent_id === "string" ? input.agent_id : "";
+          const instructions = typeof input.instructions === "string" ? input.instructions : "";
+          let resultContent: string;
+          let isError = false;
+
+          if (!requestedAgentId || !globalRegistry.getAgent(requestedAgentId) || !globalRegistry.getProviderForAgent(requestedAgentId)) {
+            isError = true;
+            resultContent = `Unknown delegated agent '${requestedAgentId || String(input.agent_id)}'.`;
+            yield { type: "error", error: resultContent };
+          } else if (delegationPath.includes(requestedAgentId)) {
+            isError = true;
+            resultContent = `Circular delegation detected for agent '${requestedAgentId}'.`;
+            yield { type: "error", error: resultContent };
+          } else if (!instructions) {
+            isError = true;
+            resultContent = "delegate_task requires non-empty instructions.";
+          } else {
+            const child = executeAgentConversation(
+              requestedAgentId,
+              instructions,
+              request,
+              abortController,
+              debugMode,
+              [...delegationPath, requestedAgentId],
+            );
+            let childNext = await child.next();
+            while (!childNext.done) {
+              // Nested failures intentionally remain tool results, except circular
+              // and unknown-agent validation errors which are stream-level errors.
+              if (childNext.value.type === "error") yield childNext.value;
+              childNext = await child.next();
+            }
+            isError = !!childNext.value.error;
+            resultContent = childNext.value.error || childNext.value.text || EMPTY_DELEGATE_RESULT;
+          }
+
+          const toolResult = {
+            type: "tool_result",
+            is_error: isError,
+            content: resultContent,
+            tool_use_id: toolUseId,
+          };
+          const feedback = JSON.stringify(toolResult);
+          yield toolResultStreamResponse(toolResult, request.sessionId);
+          resumeMessage = feedback;
+          break;
+        }
+
+        const chatRoomMessage = createChatRoomMessage(response, agentId);
+        if (chatRoomMessage) {
+          yield {
+            type: "claude_json",
+            data: { type: "chat_room_message", message: chatRoomMessage, session_id: request.sessionId },
+          };
+        }
+
+        if (response.type === "text") {
+          const text = response.content || "";
+          accumulatedText.push(text);
+          yield {
+            type: "claude_json",
+            data: { type: "assistant", content: text, model: response.metadata?.model },
+          };
+        } else if (response.type === "error") {
+          return { text: accumulatedText.join(""), error: response.error || "Agent run failed" };
+        }
+      }
+    } catch (error) {
+      return {
+        text: accumulatedText.join(""),
+        error: error instanceof Error ? error.message : String(error),
+      };
+    }
+
+    if (!resumeMessage) return { text: accumulatedText.join("") };
+    message = resumeMessage;
+  }
+}
