+/**
+ * Runs one agent turn. A delegate_task starts a nested run, then resumes this
+ * agent with the nested run's tool_result JSON as its next message.
+ */
+async function* executeAgentConversation(
+  agentId: string,
+  initialMessage: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationPath: string[],
+): AsyncGenerator<StreamResponse, AgentRunResult> {
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+  if (!provider || !agentConfig) {
+    return { text: "", error: `Agent '${agentId}' not found or provider not available` };
+  }
+
+  const accumulatedText: string[] = [];
+  let message = initialMessage;
+  let toolSequence = 0;
+
+  while (true) {
+    let resumeMessage: string | undefined;
+    try {
+      const providerRequest: ProviderChatRequest = {
+        message,
+        sessionId: request.sessionId,
+        requestId: request.requestId,
+        workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+      };
+
+      for await (const response of provider.executeChat(providerRequest, {
+        debugMode,
+        abortController,
+        temperature: agentConfig.config?.temperature,
+        maxTokens: agentConfig.config?.maxTokens,
+      })) {
+        if (response.type === "tool_use" && response.toolName === "delegate_task") {
+          const input = (response.toolInput ?? {}) as DelegateTaskInput;
+          const toolUseId = response.toolUseId || `${agentId}-delegate-${++toolSequence}`;
+          yield toolUseStreamResponse(agentId, toolUseId, input, request.sessionId);
