+          const requestedAgentId = typeof input.agent_id === "string" ? input.agent_id : "";
+          const instructions = typeof input.instructions === "string" ? input.instructions : "";
+          let resultContent: string;
+          let isError = false;
+
+          if (!requestedAgentId || !globalRegistry.getAgent(requestedAgentId) || !globalRegistry.getProviderForAgent(requestedAgentId)) {
+            isError = true;
+            resultContent = `Unknown delegated agent '${requestedAgentId || String(input.agent_id)}'.`;
+            yield { type: "error", error: resultContent };
+          } else if (delegationPath.includes(requestedAgentId)) {
+            isError = true;
+            resultContent = `Circular delegation detected for agent '${requestedAgentId}'.`;
+            yield { type: "error", error: resultContent };
+          } else if (!instructions) {
+            isError = true;
+            resultContent = "delegate_task requires non-empty instructions.";
+          } else {
+            const child = executeAgentConversation(
+              requestedAgentId,
+              instructions,
+              request,
+              abortController,
+              debugMode,
+              [...delegationPath, requestedAgentId],
+            );
+            let childNext = await child.next();
+            while (!childNext.done) {
+              // Nested failures intentionally remain tool results, except circular
+              // and unknown-agent validation errors which are stream-level errors.
+              if (childNext.value.type === "error") yield childNext.value;
+              childNext = await child.next();
+            }
+            isError = !!childNext.value.error;
+            resultContent = childNext.value.error || childNext.value.text || EMPTY_DELEGATE_RESULT;
+          }
+
+          const toolResult = {
+            type: "tool_result",
+            is_error: isError,
+            content: resultContent,
+            tool_use_id: toolUseId,
+          };
+          const feedback = JSON.stringify(toolResult);
+          yield toolResultStreamResponse(toolResult, request.sessionId);
+          resumeMessage = feedback;
