+            type: "claude_json",
+            data: { type: "chat_room_message", message: chatRoomMessage, session_id: request.sessionId },
+          };
+        }
+
+        if (response.type === "text") {
+          const text = response.content || "";
+          accumulatedText.push(text);
+          yield {
+            type: "claude_json",
+            data: { type: "assistant", content: text, model: response.metadata?.model },
+          };
+        } else if (response.type === "error") {
+          return { text: accumulatedText.join(""), error: response.error || "Agent run failed" };
+        }
+      }
+    } catch (error) {
+      return {
+        text: accumulatedText.join(""),
+        error: error instanceof Error ? error.message : String(error),
+      };
+    }
